        m.insert("openInterestAmount".to_string(), self.parse_number(openInterest.clone(), &[]));
        m.insert("openInterestValue".to_string(), self.parse_number(interestValue.clone(), &[]));
        m.insert("timestamp".to_string(), timestamp.clone());
